#include <stdio.h>

int findSingleNumber(int *arr, int n) {
    int x = 0;
    for (int i = 0; i < n; ++i) x ^= arr[i];
    return x;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int arr[15]; // N <= 15 as per problem limits
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        printf("%d\n", findSingleNumber(arr, N));
    }
    return 0;
}

